/**
 * db/build-db.js
 * ───────────────
 * Loads and provides query access to the static game data JSON files
 * in db/data/. These files are generated by extractor/extract.py and
 * must be re-run after each game patch.
 *
 * ─── Data Files ──────────────────────────────────────────────────────────────
 *
 *  db/data/passives.json   → { [nodeId: string]: PassiveNode }
 *  db/data/skills.json     → { [skillKey: string]: SkillEntry }
 *  db/data/classes.json    → { classes: { [id]: string }, masteries: { [id]: MasteryEntry } }
 *  db/data/items.json      → (future) item and affix data
 *
 * ─── PassiveNode shape ───────────────────────────────────────────────────────
 * {
 *   nodeId:      number,
 *   name:        string,
 *   description: string,
 *   maxPoints:   number,
 *   treeId:      string,   // e.g. "sentinel_base", "void_knight"
 *   treeName:    string,   // e.g. "Sentinel", "Void Knight"
 *   requires?:   number[]  // prerequisite nodeIds
 * }
 *
 * ─── SkillEntry shape ────────────────────────────────────────────────────────
 * {
 *   name:  string,
 *   nodes: { [nodeId: string]: SkillNode }
 * }
 *
 * ─── SkillNode shape ─────────────────────────────────────────────────────────
 * {
 *   nodeId:      number,
 *   name:        string,
 *   description: string,
 *   maxPoints:   number
 * }
 *
 * ─── MasteryEntry shape ──────────────────────────────────────────────────────
 * {
 *   name:    string,
 *   classId: number
 * }
 *
 * ─── Usage ───────────────────────────────────────────────────────────────────
 *
 *   const db = require('./build-db');
 *   db.load();              // call once at startup
 *
 *   db.getPassive(6)        // → PassiveNode | null
 *   db.getSkillNode('fl44', 4)  // → SkillNode | null
 *   db.getSkillName('fl44') // → "Erasing Strike" | null
 *   db.getClassName(3)      // → "Sentinel" | null
 *   db.getMasteryName(2)    // → "Void Knight" | null
 *   db.all()                // → { passives, skills, classes } — full raw DB
 *
 * NOTE: db/data/*.json files may not exist yet (they require running extractor/).
 * If files are missing, db.load() will log a warning and return empty data
 * rather than crashing. The overlay will show raw nodeIds instead of names
 * until real data is populated.
 */

'use strict';

const fs = require('fs');
const path = require('path');

const DATA_DIR = path.join(__dirname, 'data');

// ─── Internal state ───────────────────────────────────────────────────────────

let _passives = {};
let _skills = {};
let _classes = { classes: {}, masteries: {} };
let _loaded = false;

// ─── Loader ───────────────────────────────────────────────────────────────────

/**
 * Load all data files from db/data/ into memory.
 * Safe to call multiple times (only loads once unless force=true).
 *
 * @param {boolean} [force=false] - reload even if already loaded
 */
function load(force = false) {
  if (_loaded && !force) return;

  _passives = loadJsonFile('passives.json', {});
  _skills = loadJsonFile('skills.json', {});
  _classes = loadJsonFile('classes.json', { classes: {}, masteries: {} });

  _loaded = true;
  console.log(`[db] Loaded: ${Object.keys(_passives).length} passives, ${Object.keys(_skills).length} skill trees`);
}

/**
 * @private
 * Load a JSON file from DATA_DIR, returning fallback if missing/invalid.
 */
function loadJsonFile(filename, fallback) {
  const filePath = path.join(DATA_DIR, filename);
  if (!fs.existsSync(filePath)) {
    console.warn(`[db] Missing data file: ${filePath} — run extractor/extract.py to generate it`);
    return fallback;
  }
  try {
    return JSON.parse(fs.readFileSync(filePath, 'utf-8'));
  } catch (e) {
    console.error(`[db] Failed to parse ${filename}:`, e.message);
    return fallback;
  }
}

// ─── Query API ────────────────────────────────────────────────────────────────

/**
 * Look up a passive node by its numeric nodeId.
 * @param {number|string} nodeId
 * @returns {object|null} PassiveNode or null
 */
function getPassive(nodeId) {
  return _passives[String(nodeId)] ?? null;
}

/**
 * Look up a specific node within a skill tree.
 * @param {string} skillKey - e.g. "fl44"
 * @param {number|string} nodeId
 * @returns {object|null} SkillNode or null
 */
function getSkillNode(skillKey, nodeId) {
  return _skills[skillKey]?.nodes?.[String(nodeId)] ?? null;
}

/**
 * Get the display name for a skill by its key.
 * @param {string} skillKey
 * @returns {string|null}
 */
function getSkillName(skillKey) {
  return _skills[skillKey]?.name ?? null;
}

/**
 * Get the display name for a class by its ID.
 * @param {number|string} classId
 * @returns {string|null}
 */
function getClassName(classId) {
  return _classes.classes?.[String(classId)] ?? null;
}

/**
 * Get the display name for a mastery by its ID.
 * @param {number|string} masteryId
 * @returns {string|null}
 */
function getMasteryName(masteryId) {
  return _classes.masteries?.[String(masteryId)]?.name ?? null;
}

/**
 * Return the full raw DB (for passing to parser functions).
 * @returns {{ passives: object, skills: object, classes: object }}
 */
function all() {
  return { passives: _passives, skills: _skills, classes: _classes };
}

/**
 * Check whether db/data files exist and have content.
 * Useful for showing a "DB not populated" warning in the UI.
 * @returns {boolean}
 */
function isPopulated() {
  return Object.keys(_passives).length > 0 || Object.keys(_skills).length > 0;
}

// ─── Exports ──────────────────────────────────────────────────────────────────

module.exports = {
  load,
  getPassive,
  getSkillNode,
  getSkillName,
  getClassName,
  getMasteryName,
  all,
  isPopulated,
};
